mapper.select:


WITH PaginatedItems AS (
SELECT i.item_id,
       i.name,
       i.price::numeric AS price,
       i.added_at,
       i.quantity,
       i.category_id,
       i.wear_id,
       i.seller_cip,
       u.first_name,
       u.last_name,
CASE
WHEN f.added_at IS NULL THEN FALSE
WHEN f.added_at IS NOT NULL THEN TRUE
END AS item_is_favorite
FROM ebock.item i
INNER JOIN ebock.user_ u ON i.seller_cip = u.cip
LEFT JOIN ebock.favorite f ON i.item_id = f.item_id AND f.cip = #{cip}

    NOT i.sold AND NOT i.archived

        AND i.price::numeric >= #{filters.minPrice}


        AND #{filters.maxPrice} >= i.price::numeric


        AND f.added_at IS NOT NULL


        AND i.category_id IN

            #{id}



        AND i.wear_id IN

            #{id}




        AND (SELECT count(ti.tag_id)
              FROM ebock.tag_item ti
              WHERE ti.item_id = i.item_id
              AND ti.tag_id IN

                  #{id}

             ) = #{listTagSize}



        AND (SELECT count(ido.delivery_optn_id)
             FROM ebock.item_del_option ido
             WHERE ido.item_id = i.item_id
             AND ido.delivery_optn_id IN

                 #{id}

            ) = #{listDeliverySize}



        AND (SELECT count(ipo.payment_optn_id)
             FROM ebock.item_paym_option ipo
             WHERE ipo.item_id = i.item_id
             AND ipo.payment_optn_id IN

                 #{id}

            ) = #{listPaymentSize}



ORDER BY i.item_id
LIMIT #{pageSize} OFFSET #{offset}
)

SELECT p.*,
       it.tag_id
FROM PaginatedItems p
LEFT JOIN ebock.tag_item it ON p.item_id = it.item_id
ORDER BY p.item_id;

SELECT *
FROM ebock.item i
WHERE i.item_id = #{id};

SELECT COUNT(*)
FROM ebock.item i
WHERE i.item_id = #{id};
